member.example:
Bind the Behaviour enabled property using a serialized binder field — the target Behaviour is assigned in the Inspector.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private BehaviourEnabledBinder _enabled;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public bool _enabled;
    }


Bind the Behaviour enabled property by constructing the binder in code.

    [View]
    public partial class ExampleView
    {
        [SerializeField] private Behaviour _behaviour;
        
        private BehaviourEnabledBinder Enabled =>
            new(_behaviour);
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public bool _enabled;
    }
